import { useState, useCallback } from 'react';
import type { ChatMessage, ChatRequest } from '../types/chat';
import type { LoanInput, LoanSummary, PrePayment, RateChange } from '../types/loan';

interface UseChatProps {
  loan: LoanInput;
  summary: LoanSummary;
  prePayments: PrePayment[];
  rateChanges: RateChange[];
}

export const useChat = ({ loan, summary, prePayments, rateChanges }: UseChatProps) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const sendMessage = useCallback(
    async (content: string) => {
      const userMessage: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'user',
        content,
        timestamp: Date.now(),
      };

      setMessages((prev) => [...prev, userMessage]);
      setIsLoading(true);

      const assistantId = crypto.randomUUID();
      setMessages((prev) => [
        ...prev,
        { id: assistantId, role: 'assistant', content: '', timestamp: Date.now() },
      ]);

      try {
        const wp = summary.withPrePayments;
        const totalPrePaymentAmount = prePayments.reduce((sum, pp) => sum + pp.amount, 0);

        const recentMessages = [...messages, userMessage]
          .slice(-10)
          .map((m) => ({ role: m.role, content: m.content }));

        const requestBody: ChatRequest = {
          messages: recentMessages,
          loanContext: {
            principal: loan.principal,
            annualRate: loan.annualRate,
            emi: loan.emi,
            startDate: loan.startDate,
            totalInterest: wp.totalInterest,
            totalAmountPaid: wp.totalAmountPaid,
            closureDate: wp.closureDate,
            totalMonths: wp.totalMonths,
            interestSaved: summary.interestSaved,
            monthsSaved: summary.monthsSaved,
            prePaymentsCount: prePayments.length,
            totalPrePaymentAmount,
            rateChangesCount: rateChanges.length,
          },
        };

        const response = await fetch('/api/chat', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(requestBody),
        });

        if (!response.ok) {
          throw new Error('Failed to get response');
        }

        const reader = response.body?.getReader();
        if (!reader) throw new Error('No response body');

        const decoder = new TextDecoder();
        let buffer = '';

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          buffer += decoder.decode(value, { stream: true });
          const lines = buffer.split('\n');
          buffer = lines.pop() ?? '';

          for (const line of lines) {
            if (!line.startsWith('data: ')) continue;
            const data = line.slice(6).trim();
            if (data === '[DONE]') break;

            try {
              const parsed = JSON.parse(data);
              if (parsed.content) {
                setMessages((prev) =>
                  prev.map((m) =>
                    m.id === assistantId ? { ...m, content: m.content + parsed.content } : m,
                  ),
                );
              }
            } catch {
              // skip malformed chunks
            }
          }
        }
      } catch {
        setMessages((prev) =>
          prev.map((m) =>
            m.id === assistantId
              ? { ...m, content: 'Sorry, I encountered an error. Please try again.' }
              : m,
          ),
        );
      } finally {
        setIsLoading(false);
      }
    },
    [messages, loan, summary, prePayments, rateChanges],
  );

  const clearMessages = useCallback(() => {
    setMessages([]);
  }, []);

  return { messages, isLoading, sendMessage, clearMessages };
};

