  1→import { addMonths, format, parseISO, lastDayOfMonth } from 'date-fns';
  2→import type {
  3→  LoanInput,
  4→  PrePayment,
  5→  RateChange,
  6→  AmortizationRow,
  7→  AmortizationResult,
  8→} from '../types/loan';
  9→
 10→// Re-export for backward compatibility — consumers can import from here or directly
 11→export { validateLoan } from './validation';
 12→export { generateSummary } from './summary';
 13→
 14→const getEmiDate = (year: number, month: number, emiDay: number): Date => {
 15→  const lastDay = lastDayOfMonth(new Date(year, month, 1)).getDate();
 16→  return new Date(year, month, Math.min(emiDay, lastDay));
 17→};
 18→
 19→const groupPrePaymentsByMonth = (prePayments: PrePayment[]): Map<string, number> => {
 20→  const map = new Map<string, number>();
 21→  for (const pp of prePayments) {
 22→    const key = format(parseISO(pp.date), 'yyyy-MM');
 23→    map.set(key, (map.get(key) || 0) + pp.amount);
 24→  }
 25→  return map;
 26→};
 27→
 28→const buildRateByMonth = (rateChanges: RateChange[]): Map<string, number> => {
 29→  const sorted = [...rateChanges].sort(
 30→    (a, b) => new Date(a.date).getTime() - new Date(b.date).getTime(),
 31→  );
 32→  const map = new Map<string, number>();
 33→  for (const rc of sorted) {
 34→    const key = format(parseISO(rc.date), 'yyyy-MM');
 35→    map.set(key, rc.newRate);
 36→  }
 37→  return map;
 38→};
 39→
 40→const roundTwo = (n: number): number => Math.round(n * 100) / 100;
 41→
 42→const MAX_MONTHS = 600;
 43→
 44→export const calculateAmortization = (
 45→  loan: LoanInput,
 46→  prePayments: PrePayment[],
 47→  rateChanges: RateChange[] = [],
 48→): AmortizationResult => {
 49→  let currentAnnualRate = loan.annualRate;
 50→  let monthlyRate = currentAnnualRate / 100 / 12;
 51→
 52→  const ppByMonth = groupPrePaymentsByMonth(prePayments);
 53→  const rateByMonth = buildRateByMonth(rateChanges);
 54→
 55→  const startDate = parseISO(loan.startDate);
 56→  let outstanding = loan.principal;
 57→  const schedule: AmortizationRow[] = [];
 58→  let totalInterest = 0;
 59→  let totalPaid = 0;
 60→  let monthNum = 0;
 61→
 62→  let currentDate = getEmiDate(startDate.getFullYear(), startDate.getMonth(), loan.emiDebitDay);
 63→
 64→  // If start date is after the EMI day in that month, move to next month
 65→  if (currentDate < startDate) {
 66→    currentDate = addMonths(currentDate, 1);
 67→    currentDate = getEmiDate(currentDate.getFullYear(), currentDate.getMonth(), loan.emiDebitDay);
 68→  }
 69→
 70→  while (outstanding > 0.01 && monthNum < MAX_MONTHS) {
 71→    monthNum++;
 72→    const dateStr = format(currentDate, 'yyyy-MM-dd');
 73→    const monthKey = format(currentDate, 'yyyy-MM');
 74→    const openingBalance = outstanding;
 75→
 76→    // Apply rate change if scheduled this month
 77→    const newRate = rateByMonth.get(monthKey);
 78→    if (newRate !== undefined) {
 79→      currentAnnualRate = newRate;
 80→      monthlyRate = currentAnnualRate / 100 / 12;
 81→    }
 82→
 83→    // Apply pre-payment BEFORE interest calculation
 84→    // In Indian home loans, pre-payment reduces the principal immediately,
 85→    // so interest from that point is calculated on the reduced balance.
 86→    let ppAmount = 0;
 87→    const scheduledPP = ppByMonth.get(monthKey) || 0;
 88→    if (scheduledPP > 0 && outstanding > 0.01) {
 89→      ppAmount = Math.min(scheduledPP, outstanding);
 90→      outstanding -= ppAmount;
 91→      totalPaid += ppAmount;
 92→    }
 93→
 94→    const interest = outstanding * monthlyRate;
 95→    let principalPortion: number;
 96→    let emiPaid: number;
 97→
 98→    if (outstanding <= 0.01) {
 99→      emiPaid = 0;
100→      principalPortion = 0;
101→    } else if (outstanding + interest <= loan.emi) {
102→      emiPaid = outstanding + interest;
103→      principalPortion = outstanding;
104→    } else {
105→      emiPaid = loan.emi;
106→      principalPortion = loan.emi - interest;
107→    }
108→
109→    outstanding -= principalPortion;
110→    totalInterest += interest;
111→    totalPaid += emiPaid;
112→
113→    if (outstanding < 0.01) outstanding = 0;
114→
115→    schedule.push({
116→      month: monthNum,
117→      date: dateStr,
118→      openingBalance: roundTwo(openingBalance),
119→      interestComponent: roundTwo(interest),
120→      principalComponent: roundTwo(principalPortion),
121→      prePayment: roundTwo(ppAmount),
122→      totalPayment: roundTwo(emiPaid + ppAmount),
123→      closingBalance: roundTwo(outstanding),
124→      annualRate: currentAnnualRate,
125→    });
126→
127→    if (outstanding <= 0) break;
128→
129→    currentDate = addMonths(currentDate, 1);
130→    currentDate = getEmiDate(currentDate.getFullYear(), currentDate.getMonth(), loan.emiDebitDay);
131→  }
132→
133→  const lastRow = schedule[schedule.length - 1];
134→  return {
135→    schedule,
136→    totalInterest: roundTwo(totalInterest),
137→    totalAmountPaid: roundTwo(totalPaid),
138→    closureDate: lastRow?.date || loan.startDate,
139→    totalMonths: schedule.length,
140→  };
141→};
